#include <bits/stdc++.h>
using namespace std;
#define ll long long
#define vl vector<ll>
#define vb vector<bool>
#define ff(aa, bb, cc) for(ll aa = bb; aa < cc; aa++)
#define ed "\n"
#define pb push_back
#define all(aaa) aaa.begin(), aaa.end()
#define rall(aaa) aaa.rbegin(), aaa.rend()
#define fi first
#define se second
#define pll pair<ll, ll>

int main(){
	string str = "";
	ll l = 0, r = 0;
	ll w, b;
	cin >> w >> b;
	ll cw = 0, cb = 0;
	while(r < str.size()){
		if(cw == w && cb == b){
			cout << "Yes";
			return 0;
		}
		while(cw > w || cb > b){
			if(l >= str.size()){
				cout << "No";
				return 0;
			}
			if(str[l] == 'w') cw--;
			else cb--;
			l++;
		}
		if(cw == w && cb == b){
			cout << "Yes";
			return 0;
		}
		while(cw < w || cb < b){
			if(r >= str.size()){
				cout << "No";
				return 0;
			}
			if(str[r] == 'w') cw++;
			else cb++;
			r++;
		}
		if(cw == w && cb == b){
			cout << "Yes";
			return 0;
		}
	}
	cout << "No";
	
}
